const CAPTURE_MUTATION = `
  mutation CaptureBookmark($input: BookmarkInput!) {
    captureBookmark(input: $input) {
      id
      status
      title
      tags
    }
  }
`;

chrome.runtime.onMessage.addListener((message, _sender, sendResponse) => {
  if (message.action === "captureBookmark") {
    handleCapture(message.input).then(sendResponse);
    return true; // keep message channel open for async response
  }
});

async function handleCapture(input) {
  try {
    const { apiUrl, jwtToken } = await chrome.storage.local.get([
      "apiUrl",
      "jwtToken",
    ]);

    if (!apiUrl || !jwtToken) {
      return { success: false, error: "Extension not configured" };
    }

    const graphqlUrl = apiUrl.replace(/\/+$/, "") + "/graphql";

    const res = await fetch(graphqlUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: "Bearer " + jwtToken,
      },
      body: JSON.stringify({
        query: CAPTURE_MUTATION,
        variables: { input },
      }),
    });

    if (!res.ok) {
      const text = await res.text();
      return { success: false, error: `HTTP ${res.status}: ${text}` };
    }

    const json = await res.json();

    if (json.errors && json.errors.length > 0) {
      return { success: false, error: json.errors[0].message };
    }

    return { success: true, data: json.data.captureBookmark };
  } catch (err) {
    return { success: false, error: err.message };
  }
}

