document.addEventListener("DOMContentLoaded", async () => {
  const form = document.getElementById("capture-form");
  const urlInput = document.getElementById("url");
  const titleInput = document.getElementById("title");
  const selectionInput = document.getElementById("selection");
  const tagsInput = document.getElementById("tags");
  const sensitivitySelect = document.getElementById("sensitivity");
  const saveBtn = document.getElementById("save-btn");
  const statusDiv = document.getElementById("status");
  const notConfigured = document.getElementById("not-configured");
  const openOptions = document.getElementById("open-options");

  // Check if configured
  const { apiUrl, jwtToken } = await chrome.storage.local.get([
    "apiUrl",
    "jwtToken",
  ]);

  if (!apiUrl || !jwtToken) {
    notConfigured.hidden = false;
    form.hidden = true;
    openOptions.addEventListener("click", (e) => {
      e.preventDefault();
      chrome.runtime.openOptionsPage();
    });
    return;
  }

  // Get current tab info
  const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });
  if (tab) {
    urlInput.value = tab.url || "";
    titleInput.value = tab.title || "";

    // Try to get selected text from the page
    try {
      const results = await chrome.scripting.executeScript({
        target: { tabId: tab.id },
        files: ["content/content.js"],
      });
      if (results && results[0] && results[0].result) {
        selectionInput.value = results[0].result;
      }
    } catch {
      // Content script injection may fail on chrome:// or extension pages
    }
  }

  form.addEventListener("submit", async (e) => {
    e.preventDefault();
    saveBtn.disabled = true;
    saveBtn.textContent = "Saving...";
    statusDiv.hidden = true;

    const rawTags = tagsInput.value
      .split(",")
      .map((t) => t.trim())
      .filter(Boolean);

    const input = {
      url: urlInput.value,
      title: titleInput.value || null,
      selection: selectionInput.value || null,
      tags: rawTags.length > 0 ? rawTags : null,
      sensitivity: sensitivitySelect.value,
    };

    try {
      const response = await chrome.runtime.sendMessage({
        action: "captureBookmark",
        input,
      });

      if (response.success) {
        showStatus("Bookmark saved!", "success");
        saveBtn.textContent = "Saved";
      } else {
        showStatus(response.error || "Failed to save bookmark", "error");
        saveBtn.disabled = false;
        saveBtn.textContent = "Save Bookmark";
      }
    } catch (err) {
      showStatus("Extension error: " + err.message, "error");
      saveBtn.disabled = false;
      saveBtn.textContent = "Save Bookmark";
    }
  });

  function showStatus(message, type) {
    statusDiv.textContent = message;
    statusDiv.className = type;
    statusDiv.hidden = false;
  }
});

